    console.log(`✅ 配置已保存: ${robotName}`);
  } else {
    console.log('机器人名称不匹配，使用默认值');
  }

  return config;
}

// 保存到文件
saveConfigToFile, {
  const configPath = '/root/.openclaw/workspace/docs/edict-robot-config.md';
